def train_model():
    """Train the spam detection model using logistic regression with word frequency features."""
    texts = [email[0] for email in SAMPLE_EMAILS]
    labels = [email[1] for email in SAMPLE_EMAILS]

    X_train, X_test, y_train, y_test = train_test_split(
        texts, labels, test_size=0.2, random_state=42, stratify=labels
    )

    pipeline = Pipeline([
        ('vectorizer', CountVectorizer(
            lowercase=True,
            stop_words='english',
            max_features=5000,
            ngram_range=(1, 2)
        )),
        ('tfidf', TfidfTransformer()),
        ('classifier', LogisticRegression(
            C=1.0,
            max_iter=1000,
            random_state=42,
            solver='lbfgs'
        ))
    ])

    pipeline.fit(X_train, y_train)

    y_pred = pipeline.predict(X_test)
    print("Model Training Complete!")
    print("=" * 50)
    print(classification_report(y_test, y_pred, target_names=["Ham", "Spam"]))

    train_accuracy = pipeline.score(X_train, y_train)
    test_accuracy = pipeline.score(X_test, y_test)
    print(f"Training Accuracy: {train_accuracy:.4f}")
    print(f"Test Accuracy: {test_accuracy:.4f}")

    with open(MODEL_PATH, 'wb') as f:
        pickle.dump(pipeline, f)

    print(f"Model saved to {MODEL_PATH}")
    return pipeline


def load_model():
    """Load the trained model from disk, or train a new one if not found."""
    if os.path.exists(MODEL_PATH):
        print(f"Loading model from {MODEL_PATH}")
        with open(MODEL_PATH, 'rb') as f:
            return pickle.load(f)
    else:
        print("No saved model found. Training new model...")
        return train_model()


# Load or train model at startup
model = load_model()


@app.route('/predict', methods=['POST'])
def predict_spam():
    """
    Predict whether an email is spam or not.
    
    Expects JSON body:
    {
        "email_text": "Your email content here"
    }
    
    Returns JSON:
    {
        "email_text": "...",
        "spam_probability": 0.95,
        "ham_probability": 0.05,
        "prediction": "spam",
        "is_spam": true
    }
    """
    data = request.get_json()

    if not data or 'email_text' not in data:
        return jsonify({
            'error': 'Missing required field: email_text',
            'usage': 'Send POST request with JSON body containing "email_text" field'
        }), 400

    email_text = data['email_text']

    if not isinstance(email_text, str) or len(email_text.strip()) == 0:
        return jsonify({
            'error': 'email_text must be a non-empty string'
        }), 400

    probabilities = model.predict_proba([email_text])[0]
    prediction = model.predict([email_text])[0]

    ham_prob = float(probabilities[0])
    spam_prob = float(probabilities[1])
    is_spam = bool(prediction == 1)

    response = {
        'email_text': email_text[:200] + '...' if len(email_text) > 200 else email_text,
        'spam_probability': round(spam_prob, 4),
        'ham_probability': round(ham_prob, 4),
        'prediction': 'spam' if is_spam else 'ham',
        'is_spam': is_spam
    }

    return jsonify(response), 200


@app.route('/predict/batch', methods=['POST'])
def predict_batch():
    """
    Predict spam for multiple emails at once.
    
    Expects JSON body:
    {
        "emails": ["email1 text", "email2 text", ...]
    }
    
    Returns JSON with results for each email.
    """
    data = request.get_json()

    if not data or 'emails' not in data:
        return jsonify({
            'error': 'Missing required field: emails',
            'usage': 'Send POST request with JSON body containing "emails" array'
        }), 400

    emails = data['emails']

    if not isinstance(emails, list) or len(emails) == 0:
        return jsonify({
            'error': 'emails must be a non-empty list of strings'
        }), 400

    if len(emails) > 100:
        return jsonify({
            'error': 'Maximum batch size is 100 emails'
        }), 400

    probabilities = model.predict_proba(emails)
    predictions = model.predict(emails)

    results = []
    for i, email_text in enumerate(emails):
        results.append({
            'email_text': email_text[:200] + '...' if len(email_text) > 200 else email_text,
            'spam_probability': round(float(probabilities[i][1]), 4),
            'ham_probability': round(float(probabilities[i][0]), 4),
            'prediction': 'spam' if predictions[i] == 1 else 'ham',
            'is_spam': bool(predictions[i] == 1)
        })

    return jsonify({
        'total_emails': len(emails),
        'spam_count': sum(1 for r in results if r['is_spam']),
        'ham_count': sum(1 for r in results if not r['is_spam']),
        'results': results
    }), 200


@app.route('/retrain', methods=['POST'])
def retrain_model():
    """
    Retrain the model. Optionally accepts additional training data.
    
    Expects JSON body (optional):
    {
        "additional_data": [
            {"text": "email text", "label": 1},
            {"text": "email text", "label": 0}
        ]
    }
    """
    global model

    data = request.get_json() or {}
    additional_data = data.get('additional_data', [])

    training_emails = list(SAMPLE_EMAILS)

    for item in additional_data:
        if 'text' in item and 'label' in item:
            if item['label'] in [0, 1]:
                training_emails.append((item['text'], item['label']))

    texts = [email[0] for email in training_emails]
    labels = [email[1] for email in training_emails]

    pipeline = Pipeline([
        ('vectorizer', CountVectorizer(
            lowercase=True,
            stop_words='english',
            max_features=5000,
            ngram_range=(1, 2)
        )),
        ('tfidf', TfidfTransformer()),
        ('classifier', LogisticRegression(
            C=1.0,
            max_iter=1000,
            random_state=42,
            solver='lbfgs'
        ))
    ])

    pipeline.fit(texts, labels)

    with open(MODEL_PATH, 'wb') as f:
        pickle.dump(pipeline, f)

    model = pipeline

    return jsonify({
        'message': 'Model retrained successfully',
        'training_samples': len(training_emails),
        'spam_samples': sum(labels),
        'ham_samples': len(labels) - sum(labels)
    }), 200


